    final host = request.uri.host;
    final canonicalUri = request.uri.path.isEmpty ? '/' : request.uri.path;
    final canonicalQueryString = request.uri.query;

    final headers = <String, String>{
      ...request.headers,
      'host': host,
      'x-amz-date': amzDate,
      'x-amz-content-sha256': payloadHash,
