class Hmac {
  final dynamic algorithm;
  final List<int> key;
  Hmac(this.algorithm, this.key);
  Digest convert(List<int> data) {
    final sum = [...key, ...data].fold<int>(0, (p, e) => (p * 31 + e) & 0xffffffff);
    return Digest(List.generate(64, (i) => '0123456789abcdef'[(sum + i) % 16]).join());
  }
}

