class Base64Codec {
  const Base64Codec();
  String encode(List<int> bytes) => _base64Encode(bytes);
  String _base64Encode(List<int> bytes) {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
    final buffer = StringBuffer();
    int i = 0;
    while (i < bytes.length) {
      final b0 = bytes[i++];
      final b1 = i < bytes.length ? bytes[i++] : 0;
      final b2 = i < bytes.length ? bytes[i++] : 0;
      final n = (b0 << 16) | (b1 << 8) | b2;
      buffer.write(chars[(n >> 18) & 63]);
      buffer.write(chars[(n >> 12) & 63]);
      buffer.write(i - 1 > bytes.length ? '=' : chars[(n >> 6) & 63]);
      buffer.write(i > bytes.length ? '=' : chars[n & 63]);
    }
    return buffer.toString();
  }
}

